import React, { useState, useCallback, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { 
  ShieldCheck, Calculator, AlertCircle, CheckCircle, Loader2, 
  Banknote, CreditCard, ArrowLeft, ChevronRight 
} from 'lucide-react';

import PageHeader from '../layout/PageHeader';
import PageContainer from '../layout/PageContainer';
import BalanceCard from './BalanceCard';
import WalletForm from './WalletForm';
import Toast from '../ui/Toast';
import { formatCurrency } from '../../utils/currency';
import { WITHDRAW_METHODS, validateAmount, validateAccount } from '../../api/validators';
import { withdrawFunds } from '../../api/wallet';

import '../../styles/WithdrawPage.css';

/**
 * WithdrawPage Component
 * Standalone page for processing wallet withdrawals
 * 
 * @param {Object} props
 * @param {number} props.availableBalance - Available balance for withdrawal
 * @param {number} props.pendingBalance - Pending balance (optional)
 * @param {string} props.currency - Currency code (USD, EUR, etc.)
 * @param {Array} props.savedAccounts - Previously saved bank accounts
 * @param {function} props.onSuccess - Callback on successful withdrawal
 * @param {function} props.onCancel - Callback on page cancel/back
 */
export default function WithdrawPage({
  availableBalance = 0,
  pendingBalance = 0,
  currency = 'USD',
  savedAccounts = [],
  onSuccess,
  onCancel
}) {
  const { t } = useTranslation();
  
  const [formData, setFormData] = useState({
    amount: '',
    method: savedAccounts.length > 0 ? 'saved_account' : 'bank',
    useSavedAccount: savedAccounts.length > 0,
    accountNumber: '',
    accountName: '',
    bankName: '',
    swiftCode: ''
  });
  
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [toast, setToast] = useState({ show: false, message: '', type: 'success' });

  const showToast = useCallback((message, type = 'success') => {
    setToast({ show: true, message, type });
    setTimeout(() => setToast(prev => ({ ...prev, show: false })), 4500);
  }, []);

  const handleFieldChange = useCallback((field, value) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    if (errors[field]) setErrors(prev => ({ ...prev, [field]: null }));
  }, [errors]);

  const validateForm = useCallback(() => {
    const newErrors = {};
    
    // Amount validation
    const amountVal = validateAmount(formData.amount, {
      min: 10,
      max: availableBalance,
      currency,
      isWithdraw: true
    });
    if (!amountVal.valid) newErrors.amount = amountVal.error;
    
    // Account validation (if new account selected)
    if (formData.method === 'bank' && !formData.useSavedAccount) {
      const accVal = validateAccount({
        accountNumber: formData.accountNumber,
        accountName: formData.accountName,
        bankName: formData.bankName
      });
      if (!accVal.valid) newErrors.account = accVal.error;
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [formData, availableBalance, currency]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateForm()) {
      showToast(t('wallet.errors.formInvalid'), 'error');
      return;
    }
    
    setLoading(true);
    try {
      const amount = parseFloat(formData.amount);
      const fee = Math.max(1, amount * 0.02); // 2% fee, $1 minimum
      
      await withdrawFunds({
        amount,
        currency,
        method: formData.method === 'saved_account' ? 'bank' : formData.method,
        accountId: formData.method === 'saved_account' ? 'saved' : undefined,
        ...(formData.method === 'bank' && !formData.useSavedAccount && {
          account: {
            number: formData.accountNumber,
            name: formData.accountName,
            bank: formData.bankName,
            swift: formData.swiftCode
          }
        })
      });
      
      showToast(t('wallet.success.withdrawRequested', { 
        amount: formatCurrency(amount, currency) 
      }), 'success');
      
      onSuccess?.({
        amount,
        fee,
        net: amount - fee,
        method: formData.method
      });
      
    } catch (err) {
      console.error('Withdrawal failed:', err);
      showToast(err.message || t('wallet.errors.transactionFailed'), 'error');
    } finally {
      setLoading(false);
    }
  };

  const calculation = useMemo(() => {
    const amount = parseFloat(formData.amount) || 0;
    const fee = amount > 0 ? Math.max(1, amount * 0.02) : 0;
    return {
      amount: amount.toFixed(2),
      fee: fee.toFixed(2),
      net: Math.max(0, amount - fee).toFixed(2),
      days: WITHDRAW_METHODS[formData.method.toUpperCase()]?.estimatedDays || '2-3'
    };
  }, [formData.amount, formData.method]);

  const formSummary = formData.amount && parseFloat(formData.amount) > 0 ? {
    [t('wallet.requestedAmount')]: formatCurrency(parseFloat(calculation.amount), currency),
    [t('wallet.fee')]: `-${formatCurrency(parseFloat(calculation.fee), currency)}`,
    [t('wallet.netAmount')]: formatCurrency(parseFloat(calculation.net), currency)
  } : null;

  return (
    <PageContainer className="withdraw-page">
      <PageHeader
        title={t('wallet.withdraw')}
        showBackButton
        onBack={onCancel}
        rightContent={
          <button className="btn-icon" onClick={onCancel} aria-label={t('common.close')}>
            <ChevronRight size={20} />
          </button>
        }
      />

      {/* Balance Overview */}
      <div className="withdraw-balance-preview">
        <BalanceCard
          balance={availableBalance + pendingBalance}
          currency={currency}
          availableBalance={availableBalance}
          pendingBalance={pendingBalance}
          isVerified={true}
          onAddFunds={() => {}}
          onWithdraw={() => {}}
          canWithdraw={availableBalance >= 10}
        />
      </div>

      {/* Withdrawal Form */}
      <form onSubmit={handleSubmit} className="withdraw-form">
        <div className="form-card">
          <WalletForm
            formData={formData}
            errors={errors}
            onChange={handleFieldChange}
            onSubmit={(e) => e.preventDefault()} // Handled manually for validation control
            currency={currency}
            loading={loading}
          >
            {/* Amount Field */}
            <div className="form-group amount-section">
              <label className="form-label" htmlFor="amount">
                {t('wallet.withdrawAmount')}
                <span className="required">*</span>
              </label>
              <div className="amount-input-wrapper">
                <span className="currency-prefix">{currency}</span>
                <input
                  id="amount"
                  type="number"
                  step="0.01"
                  min="10"
                  max={availableBalance}
                  value={formData.amount}
                  onChange={(e) => handleFieldChange('amount', e.target.value)}
                  placeholder="0.00"
                  required
                  disabled={loading}
                  className={`form-input ${errors.amount ? 'error' : ''}`}
                />
                <button
                  type="button"
                  className="btn-max"
                  onClick={() => handleFieldChange('amount', availableBalance.toString())}
                  disabled={loading}
                >
                  {t('wallet.max')}
                </button>
              </div>
              {errors.amount && (
                <p className="form-error" role="alert">
                  <AlertCircle size={14} /> {errors.amount}
                </p>
              )}
              <p className="field-hint">
                {t('wallet.minWithdraw', { min: formatCurrency(10, currency) })} • 
                {t('wallet.maxWithdraw', { max: formatCurrency(availableBalance, currency) })}
              </p>
            </div>

            {/* Withdrawal Method */}
            <div className="form-group">
              <label className="form-label">{t('wallet.withdrawTo')}</label>
              <div className="method-selector">
                {[
                  { id: 'saved_account', icon: <Banknote size={20} />, label: t('wallet.savedAccount'), disabled: savedAccounts.length === 0 },
                  { id: 'bank', icon: <Banknote size={20} />, label: t('wallet.newBank') },
                  { id: 'card', icon: <CreditCard size={20} />, label: t('wallet.originalCard') }
                ].map((method) => (
                  <button
                    key={method.id}
                    type="button"
                    className={`method-option ${formData.method === method.id ? 'selected' : ''} ${method.disabled ? 'disabled' : ''}`}
                    onClick={() => handleFieldChange('method', method.id)}
                    disabled={loading || method.disabled}
                  >
                    <span className="method-icon">{method.icon}</span>
                    <span className="method-label">{method.label}</span>
                    {formData.method === method.id && <CheckCircle size={16} className="method-check" />}
                  </button>
                ))}
              </div>
            </div>

            {/* Saved Account Preview */}
            {formData.method === 'saved_account' && savedAccounts.length > 0 && (
              <div className="saved-account-preview">
                <div className="account-details">
                  <Banknote size={18} className="account-icon" />
                  <div>
                    <p className="account-name">{savedAccounts[0].name}</p>
                    <p className="account-number">•••• {savedAccounts[0].number.slice(-4)}</p>
                  </div>
                </div>
                <button 
                  type="button" 
                  className="btn-text"
                  onClick={() => handleFieldChange('method', 'bank')}
                >
                  {t('common.change')}
                </button>
              </div>
            )}

            {/* New Bank Account Details */}
            {formData.method === 'bank' && (
              <div className="account-fields">
                <div className="form-group">
                  <label className="form-label">{t('wallet.accountNumber')}</label>
                  <input
                    type="text"
                    value={formData.accountNumber}
                    onChange={(e) => handleFieldChange('accountNumber', e.target.value.replace(/\D/g, ''))}
                    placeholder="0000 0000 0000"
                    maxLength={20}
                    disabled={loading}
                  />
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">{t('wallet.accountName')}</label>
                    <input
                      type="text"
                      value={formData.accountName}
                      onChange={(e) => handleFieldChange('accountName', e.target.value)}
                      placeholder={t('wallet.accountNamePlaceholder')}
                      disabled={loading}
                    />
                  </div>
                  <div className="form-group">
                    <label className="form-label">{t('wallet.bankName')}</label>
                    <input
                      type="text"
                      value={formData.bankName}
                      onChange={(e) => handleFieldChange('bankName', e.target.value)}
                      placeholder={t('wallet.bankNamePlaceholder')}
                      disabled={loading}
                    />
                  </div>
                </div>
                <div className="form-group">
                  <label className="form-label">{t('wallet.swiftCode')} <span className="optional">(Optional)</span></label>
                  <input
                    type="text"
                    value={formData.swiftCode}
                    onChange={(e) => handleFieldChange('swiftCode', e.target.value.toUpperCase().replace(/[^A-Z0-9]/g, ''))}
                    placeholder="SWIFT / BIC"
                    maxLength={11}
                    disabled={loading}
                  />
                </div>
              </div>
            )}

            {/* Calculation Preview */}
            {calculation.amount > 0 && (
              <div className="calc-preview">
                <div className="calc-header">
                  <Calculator size={16} />
                  <span>{t('wallet.withdrawalPreview')}</span>
                </div>
                <div className="calc-row">
                  <span>{t('wallet.amount')}</span>
                  <span>{formatCurrency(parseFloat(calculation.amount), currency)}</span>
                </div>
                <div className="calc-row fee">
                  <span>{t('wallet.fee')} (2%)</span>
                  <span>- {formatCurrency(parseFloat(calculation.fee), currency)}</span>
                </div>
                <div className="calc-row net">
                  <span>{t('wallet.netAmount')}</span>
                  <span className="net-value">{formatCurrency(parseFloat(calculation.net), currency)}</span>
                </div>
                <p className="calc-footer">
                  {t('wallet.estimatedArrival', { 
                    days: calculation.days,
                    method: formData.method === 'card' ? t('wallet.card') : t('wallet.bankTransfer')
                  })}
                </p>
              </div>
            )}
          </WalletForm>
        </div>

        {/* Security & Limits */}
        <div className="security-notice">
          <ShieldCheck size={16} className="notice-icon" />
          <div className="notice-content">
            <p className="notice-title">{t('wallet.withdrawalSecurity')}</p>
            <p className="notice-text">
              {t('wallet.dailyLimit', { limit: formatCurrency(5000, currency) })} • 
              {t('wallet.monthlyLimit', { limit: formatCurrency(50000, currency) })}
            </p>
          </div>
        </div>

        {/* Submit Button */}
        <div className="form-actions">
          <button 
            type="button" 
            className="btn btn-outline" 
            onClick={onCancel}
            disabled={loading}
          >
            {t('common.cancel')}
          </button>
          <button 
            type="submit" 
            className="btn btn-primary btn-withdraw"
            disabled={loading || !formData.amount}
          >
            {loading ? (
              <>
                <Loader2 size={16} className="btn-spinner" />
                {t('common.processing')}
              </>
            ) : (
              <>
                {t('wallet.confirmWithdraw')}
                <ArrowLeft size={16} />
              </>
            )}
          </button>
        </div>
      </form>

      {/* Toast Notification */}
      <Toast
        message={toast.message}
        type={toast.type}
        isVisible={toast.show}
        onClose={() => setToast(prev => ({ ...prev, show: false }))}
      />
    </PageContainer>
  );
}
